    "created_at"        TIMESTAMP,
    "updated_at"        TIMESTAMP,
    PRIMARY KEY ("id")
);
CREATE UNIQUE INDEX IF NOT EXISTS users_email_unique ON "users" ("email");

CREATE TABLE IF NOT EXISTS "roles" (
